  ('disabled-0a2fc18c-moex-00056', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '根據凱因斯流動性偏好理論，當市場預期聯邦準備理事會升息已達高點， 對經濟體系的影響為何？', '["升息造成資本損失，降低對債券的需求", "升息導致企業營運提高，降低對債券的需求", "提高債券需求，伺機賺取利率反轉的資本利得", "提高債券需求，賺取既有債券因升息而增加的利息收益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00057', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '若生產函數為Y=AK0.6 L0.4，其中Y、A、K、L分別為經濟整體產出、總 要素生產力、資本與勞動。當經濟成長率為6%，資本成長率為5%，勞動 成長率為5%，則總要素生產力的成長率為何？', '["1%", "5%", "6%", "11%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00058', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '當中央銀行在外匯市場大量賣出外匯，另一方面又採取公開市場買進票 券，則最不可能發生下列何種現象？', '["新臺幣升值", "貿易順差擴大", "中央銀行國外資產減少", "準備貨幣減少的幅度小於中央銀行國外資產減少的幅度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00059', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '有關經濟體系中各個市場之敘述，下列何者錯誤？', '["商品市場決定相對價格水準", "外匯市場決定名目匯率", "貨幣市場決定名目利率", "勞動市場決定名目工資率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00060', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '根據「理性預期」（rationalexpectations）學派的觀點，若中央銀行採行擴 張性貨幣政策，則下列何種結果會發生？', '["不論人們有無預期到此一經濟政策，產出均不變", "不論人們有無預期到此一經濟政策，產出均增加", "若人們預期到此一經濟政策，則產出不變；若人們未預期到此一經濟政 策，則產出增加", "若人們預期到此一經濟政策，則產出增加；若人們未預期到此一經濟政 策，則產出不變"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00061', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '有關李嘉圖均等定理（RicardianEquivalenceTheory），下列敘述何者錯誤？', '["當政府減稅且未削減政府支出，民間消費不受影響", "對消費者而言，以負債融通政府支出等同於以稅收融通政府支出", "當政府減稅且未削減政府支出，民間儲蓄增加", "消費者偏好以負債融通政府支出而較不喜歡以稅收融通政府支出"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00062', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '根據MiltonFriedman的恆常所得理論（PermanentIncomeTheory），當恆 常所得的邊際消費傾向為 0.9，當期所得為 55,000 元，其中 5,000 元為臨 時所得，當期消費為何？', '["5,000元", "45,000元", "49,500元", "50,000元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00063', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '假設A公司現在與未來的資本邊際生產力 =1000-0.5K+2 L，K為資本， L 為勞動。勞動邊際生產力 =100-2L+K。若每單位資本的價格為 1,000 元，實質利率為 2%，資本折舊率每年為 5%，實質工資率為 95 元，物價 假設為1，則A公司的每單位資本使用價格為何？', '["50元", "70元", "95元", "1,000元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL)
